const r = $json;
if (!r.total || r.total === 0) return [];
return r.results.map(d => ({
  json: {
    dealId: d.id,
    dealName: d.properties.dealname || 'Sem nome',
    contatoNome: d.properties.contato_nome || '',
    contatoWhatsapp: d.properties.contato_whatsapp || '',
    segmento: d.properties.segmento || '',
    website: d.properties.website || '',
    pontoDeDor: d.properties.ponto_de_dor || '',
    pontoDorValidado: d.properties.ponto_dor_validado || '',
    ganchoMira: d.properties.gancho_mira || '',
    canalOutbound: d.properties.canal_outbound || 'WhatsApp'
  }
}));

const d = $json;

const system = `Você é NOVA, representante comercial da Carbon Films — agência de marketing visual cinematográfico em Santa Catarina, Brasil. Sua tarefa é escrever a mensagem de PRIMEIRO CONTATO via WhatsApp para um prospect.

Regras INEGOCIÁVEIS:
- Inicie com [NOVA]:
- Máximo 3 parágrafos curtos
- Use o gancho da MIRA como base — não invente outro
- Tom consultivo: você identificou um problema, não está 'vendendo'
- Termine com UMA pergunta aberta
- Nunca mencione preço ou pacotes
- Nunca use: 'transforme', 'resultados incríveis', 'clique aqui'
- Nada genérico — cada palavra deve fazer sentido para ESTA empresa específica

Responda SOMENTE com o texto da mensagem, sem explicações ou markdown.`;

const user = `Escreva a mensagem para:
- Prospect: ${d.contatoNome || d.dealName}
- Empresa: ${d.dealName}
- Segmento: ${d.segmento}
- Gancho MIRA: ${d.ganchoMira}
- Ponto de dor: ${d.pontoDorValidado || d.pontoDeDor}
- Canal: WhatsApp`;

return [{
  json: {
    ...d,
    claudeBody: JSON.stringify({
      model: 'claude-sonnet-4-5',
      max_tokens: 400,
      system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const response = $json;
const prev = $('Preparar Prompt NOVA').first().json;

let mensagem = '';
try {
  mensagem = response.content[0].text.trim();
} catch(e) {
  mensagem = `[NOVA]: Olá, ${prev.contatoNome || prev.dealName}! Vi o trabalho de vocês e tenho uma ideia que pode fazer sentido para a ${prev.dealName}. Vale uma conversa rápida?`;
}

const now = Date.now();

return [{
  json: {
    ...prev,
    mensagemNova: mensagem,
    dataUltimoContato: String(now),
    whatsappBody: JSON.stringify({
      to: prev.contatoWhatsapp,
      type: 'text',
      text: { body: mensagem }
    }),
    hubspotUpdateBody: JSON.stringify({
      properties: {
        draft_nova: mensagem,
        data_ultimo_contato: String(now),
        dealstage: $vars.HUBSPOT_STAGE_AGUARDANDO
      }
    }),
    hubspotNoteBody: JSON.stringify({
      engagement: { active: true, type: 'NOTE' },
      associations: { dealIds: [Number(prev.dealId)] },
      metadata: { body: `[NOVA - D+0]: Primeiro contato enviado via WhatsApp.\n\nMensagem enviada:\n${mensagem}` }
    })
  }
}];
